use std::fmt;

#[derive(Debug)]
struct InvalidDurationError { 
    given: u64,
}

impl fmt::Display for InvalidDurationError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Cannot set duration to an invalid value of {}.", self.given)
    }
}

impl std::error::Error for InvalidDurationError {}

#[derive(thiserror::Error, Debug)]
enum TimerError {
    #[error("A file operation failed: {0}")]
    Io(#[from] std::io::Error),

    #[error("{0}: {1}")]
    InvalidDuration(u64, InvalidDurationError),
}

fn process_timer_setup(start_time: u64) -> Result<(), TimerError> {
    if start_time == 0 {
        return Err(TimerError::InvalidDuration(start_time, InvalidDurationError { given: start_time }));
    }
    println!("Successfully validated timer setup for {} units.", start_time);
    Ok(())
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    match process_timer_setup(15) {
        Ok(_) => println!("Timer initialized successfully."),
        Err(e) => eprintln!("Initialization Error: {}", e),
    }

    match process_timer_setup(0) {
        Ok(_) => (),
        Err(e) => eprintln!("Initialization Error: {}", e),
    }

    Ok(())
}

use std::fs::File;
use std::io::{self, Read};
use thiserror::Error;

#[derive(Error, Debug)]
struct ConfigError { 
    source: Box<dyn std::error::Error + Send + Sync>,
}

impl std::fmt::Display for ConfigError {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        write!(f, "{}", self.source)
    }
}

impl From<io::Error> for ConfigError {
    fn from(e: io::Error) -> Self {
        ConfigError { source: Box::new(e) }
    }
}

#[derive(Error, Debug)]
enum LintErrorKind {
    #[error("Missing required setting: {0}")]
    MissingSetting(&'static str),
    #[error("Invalid value found for key '{0}': expected type {1}, got literal text.")]
    TypeMismatch(&'static str, &'static str),
}

#[derive(Error, Debug)]
enum ConfigLoadError {
    #[error("File system issue occurred: {0}")]
    Io(#[from] io::Error),
    #[error("Configuration structure is malformed: {0}")]
    Parsing(LintErrorKind),
}

fn load_and_check_config(path: &str) -> Result<String, ConfigLoadError> {
    let mut file = File::open(path)?;
    let mut contents = String::new();
    file.read_to_string(&mut contents)?;

    if !contents.contains("[server]") {
        return Err(ConfigLoadError::Parsing(LintErrorKind::MissingSetting("server")));
    }

    Ok(format!("Successfully read and validated configuration content from {}.", path))
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let result = load_and_check_config("./bad_config.toml");
    match result {
        Ok(message) => println!("Success: {}", message),
        Err(e) => eprintln!("Failed to process config: {}", e),
    }
    Ok(())
}

