#[derive(Error, Debug)]
pub enum BusError {
    #[error("CRC mismatch detected on data read: expected {0}, got {1}")]
    CrcMismatch(u16, u16),
    #[error("Timeout while reading status register. Did not get expected interrupt signal.")]
    Timeout,
    #[error("Bus communication failed during transaction setup: peripheral disconnected?")]
    PeripheralFailure,
}

pub fn process_data_read(crc_ok: bool, timeout_occurred: bool) -> Result<(), BusError> {
    if !crc_ok {
        return Err(BusError::CrcMismatch(0xAAAA, 0xBBBB));
    }
    if timeout_occurred {
        return Err(BusError::Timeout);
    }
    Ok(())
}

pub fn main() {
    match process_data_read(true, false) {
        Ok(()) => println!("Data processing successful."),
        Err(e) => eprintln!("Firmware error encountered: {}", e),
    }
}

use thiserror::Error;

#[derive(Debug, Error)]
pub enum VaultError {
    #[error("I/O operation failed: {0}")]
    Io(#[from] std::io::Error),
    #[error("The key derivation resulted in a zero vector during computation.")]
    ZeroVector,
    #[error("Input dimensions were inconsistent, causing rank deficiency.")]
    RankDeficient(u32),
}

fn process_vault_data(input_size: u32) -> Result<(), VaultError> {
    if input_size == 0 {
        return Err(VaultError::ZeroVector);
    }

    let _ = std::fs::read_to_string("nonexistent_file.dat").map_err(VaultError::Io);

    if input_size > 100 {
        return Err(VaultError::RankDeficient(input_size));
    }

    Ok(())
}

fn main() {
    match process_vault_data(50) {
        Ok(_) => println!("Data processing succeeded."),
        Err(e) => eprintln!("Failed to process vault data: {}", e),
    }
    match process_vault_data(200) {
        Ok(_) => (),
        Err(e) => eprintln!("Caught expected error for large input: {}", e),
    }
}
